import{_ as d,C as e,o as l,c as g,a4 as r,E as a,j as o,a as c}from"./chunks/framework.BybBnFXO.js";const _=JSON.parse('{"title":"Grading","description":"","frontmatter":{},"headers":[],"relativePath":"en/grading/intro.md","filePath":"en/grading/intro.md","lastUpdated":1784099707000}'),h={name:"en/grading/intro.md"};function u(m,t,p,b,y,f){const i=e("ColorGradeTable"),n=e("ClarityScale"),s=e("ColorWheel");return l(),g("div",null,[t[0]||(t[0]=r('<h1 id="grading" tabindex="-1">Grading <a class="header-anchor" href="#grading" aria-label="Permalink to &quot;Grading&quot;">​</a></h1><blockquote><p><em>Carat, Color, Clarity, Cut — the four measurements that move price.</em></p></blockquote><p>Gem grading evaluates stones against standardized scales so buyers and sellers can compare across regions and time. The two dominant systems are the GIA 4Cs for diamonds and the hue/tone/saturation model for colored stones.</p><h2 id="gia-4cs-diamond" tabindex="-1">GIA 4Cs (Diamond) <a class="header-anchor" href="#gia-4cs-diamond" aria-label="Permalink to &quot;GIA 4Cs (Diamond)&quot;">​</a></h2><p>The 4Cs framework, established by the Gemological Institute of America in 1953, is the global standard for diamond grading.</p><h3 id="carat-weight" tabindex="-1">Carat (Weight) <a class="header-anchor" href="#carat-weight" aria-label="Permalink to &quot;Carat (Weight)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Unit</th><th>Grams</th><th>Notes</th></tr></thead><tbody><tr><td>1 carat (ct)</td><td>0.2 g</td><td>Standard trade unit</td></tr><tr><td>1 point (pt)</td><td>0.01 ct = 0.002 g</td><td>Used for sub-carat stones</td></tr></tbody></table><p>Price increases exponentially with weight because larger rough is exponentially rarer.</p><h3 id="color-d-z-scale" tabindex="-1">Color (D-Z Scale) <a class="header-anchor" href="#color-d-z-scale" aria-label="Permalink to &quot;Color (D-Z Scale)&quot;">​</a></h3>',9)),a(i,{locale:"en"}),t[1]||(t[1]=o("p",null,'D = absolutely colorless (rarest and most valuable). Z = light yellow or brown tint, still considered "normal" diamond color.',-1)),t[2]||(t[2]=o("h3",{id:"clarity-fl–i3-scale",tabindex:"-1"},[c("Clarity (FL–I3 Scale) "),o("a",{class:"header-anchor",href:"#clarity-fl–i3-scale","aria-label":'Permalink to "Clarity (FL–I3 Scale)"'},"​")],-1)),a(n,{locale:"en"}),t[3]||(t[3]=r('<p>Inclusions and blemishes are evaluated at 10× magnification. FL through VVS is considered eye-clean; SI shows inclusions under 10×; I shows inclusions to the naked eye.</p><h3 id="cut-quality" tabindex="-1">Cut (Quality) <a class="header-anchor" href="#cut-quality" aria-label="Permalink to &quot;Cut (Quality)&quot;">​</a></h3><p>Distinct from shape (round, princess, oval, etc.). Cut grade evaluates proportions, symmetry, and polish:</p><table tabindex="0"><thead><tr><th>Grade</th><th>Description</th></tr></thead><tbody><tr><td><strong>Excellent</strong></td><td>Reflects nearly all light that enters; maximum fire and brilliance</td></tr><tr><td><strong>Very Good</strong></td><td>Reflects most light; some loss at pavilion</td></tr><tr><td><strong>Good</strong></td><td>Acceptable brilliance; some light leakage</td></tr><tr><td><strong>Fair</strong></td><td>Visible light leakage; dull appearance</td></tr><tr><td><strong>Poor</strong></td><td>Most light escapes; stone appears dark or glassy</td></tr></tbody></table><h2 id="fancy-color-grading-colored-stones" tabindex="-1">Fancy Color Grading (Colored Stones) <a class="header-anchor" href="#fancy-color-grading-colored-stones" aria-label="Permalink to &quot;Fancy Color Grading (Colored Stones)&quot;">​</a></h2><p>Colored stones (Ruby, Sapphire, Emerald, etc.) use a different system based on three dimensions:</p><h3 id="hue-color-itself" tabindex="-1">Hue (Color Itself) <a class="header-anchor" href="#hue-color-itself" aria-label="Permalink to &quot;Hue (Color Itself)&quot;">​</a></h3>',7)),a(s,{locale:"en"}),t[4]||(t[4]=r('<p>Hue = the basic color (red, green, blue, etc.) as positioned on the color wheel.</p><h3 id="tone-lightness" tabindex="-1">Tone (Lightness) <a class="header-anchor" href="#tone-lightness" aria-label="Permalink to &quot;Tone (Lightness)&quot;">​</a></h3><p>Tone is the position on a white-to-black scale. Categorized as:</p><ul><li><strong>Very Light</strong> (0–20% grey)</li><li><strong>Light</strong> (20–40%)</li><li><strong>Medium-Light</strong> (40–60%)</li><li><strong>Medium</strong> (60%)</li><li><strong>Medium-Dark</strong> (60–80%)</li><li><strong>Dark</strong> (80–90%)</li><li><strong>Very Dark</strong> (90–100%)</li></ul><p>The color wheel&#39;s center disc represents tone, ranging from light at the top to dark at the bottom.</p><h3 id="saturation-intensity" tabindex="-1">Saturation (Intensity) <a class="header-anchor" href="#saturation-intensity" aria-label="Permalink to &quot;Saturation (Intensity)&quot;">​</a></h3><p>Saturation describes color purity:</p><ul><li><strong>Pastel</strong> — soft, low chroma</li><li><strong>Moderate</strong> — clear color</li><li><strong>Vivid</strong> — strong, pure color</li><li><strong>Intense</strong> — exceptional color</li><li><strong>Deep</strong> — very dark and rich</li></ul><blockquote><p>For most colored stones, the <strong>vivid / intense</strong> combination commands the highest premium. A vivid red Ruby can be worth 50× more than a dark red Ruby of equal carat weight.</p></blockquote><h2 id="treatment-disclosure" tabindex="-1">Treatment Disclosure <a class="header-anchor" href="#treatment-disclosure" aria-label="Permalink to &quot;Treatment Disclosure&quot;">​</a></h2><p>The Laboratory Manual Harmonisation Committee (LMHC) standardizes how treatments are disclosed in gemstone reports. Common disclosed treatments include:</p><table tabindex="0"><thead><tr><th>Treatment</th><th>Typical For</th><th>Disclosure</th></tr></thead><tbody><tr><td><strong>Heat</strong></td><td>Ruby, Sapphire, Tanzanite</td><td>Universal acceptance</td></tr><tr><td><strong>Filling (oil/resin)</strong></td><td>Emerald</td><td>Standard for fissures</td></tr><tr><td><strong>HPHT</strong></td><td>Diamond</td><td>Required disclosure</td></tr><tr><td><strong>Irradiation</strong></td><td>Blue Topaz, some Tourmaline</td><td>Required disclosure</td></tr><tr><td><strong>Diffusion</strong></td><td>Sapphire (surface color)</td><td>Required disclosure</td></tr><tr><td><strong>Coating</strong></td><td>Various</td><td>Required disclosure</td></tr></tbody></table><p>Untreated stones command significant premiums. LMHC-recommended disclosure language: &quot;No indications of heating&quot; (NTE).</p><h2 id="origin-premiums" tabindex="-1">Origin Premiums <a class="header-anchor" href="#origin-premiums" aria-label="Permalink to &quot;Origin Premiums&quot;">​</a></h2><p>For some gems, geographic origin dramatically affects value:</p><table tabindex="0"><thead><tr><th>Gem</th><th>Premium Origin</th><th>Standard Origin</th></tr></thead><tbody><tr><td><strong>Ruby</strong></td><td>Burma (Mogok, Mong Hsu)</td><td>Mozambique, Thailand</td></tr><tr><td><strong>Sapphire</strong></td><td>Kashmir, Burma</td><td>Sri Lanka, Madagascar</td></tr><tr><td><strong>Emerald</strong></td><td>Colombia (Muzo, Chivor)</td><td>Zambia, Brazil</td></tr><tr><td><strong>Alexandrite</strong></td><td>Russia (Ural)</td><td>Brazil, Sri Lanka</td></tr><tr><td><strong>Paraíba Tourmaline</strong></td><td>Brazil (Paraíba state)</td><td>Mozambique, Nigeria</td></tr><tr><td><strong>Tanzanite</strong></td><td>Tanzania (Merelani)</td><td>(single source)</td></tr></tbody></table><p>Origin determination requires sophisticated trace-element analysis (LA-ICP-MS) and may require comparison with reference stones of known provenance.</p><h2 id="how-to-read-a-grading-report" tabindex="-1">How to Read a Grading Report <a class="header-anchor" href="#how-to-read-a-grading-report" aria-label="Permalink to &quot;How to Read a Grading Report&quot;">​</a></h2><p>A typical lab report includes:</p><ol><li><strong>Identification</strong> — species and variety</li><li><strong>Weight</strong> — carat to 2 decimal places</li><li><strong>Dimensions</strong> — length × width × depth (mm)</li><li><strong>Color grade</strong> — letter (D–Z) + descriptive text for fancy</li><li><strong>Clarity grade</strong> — FL/IF/VVS/VS/SI/I + sub-grade</li><li><strong>Cut grade</strong> — Excellent/Very Good/Good/Fair/Poor</li><li><strong>Polish / Symmetry</strong> — Excellent/Very Good/Good/Fair</li><li><strong>Fluorescence</strong> — None/Faint/Medium/Strong</li><li><strong>Comments</strong> — treatments, origin, special features</li><li><strong>Reference numbers and lab logo</strong></li></ol>',20))])}const q=d(h,[["render",u]]);export{_ as __pageData,q as default};
